/**
 * Tax சேர்த்து total price calculate பண்ணும்.
 * @param {number} price - Base price (dollars-ல)
 * @param {number} taxRate - Tax rate as decimal (e.g. 0.08 for 8%)
 * @returns {number} Tax சேர்த்த total price
 */
function calculateTotal(price, taxRate) {
  return price * (1 + taxRate);
}

// இப்போ VS Code hints காட்டும்:
calculateTotal(100, 0.08); // returns 108

// var — function-scoped, modern code-ல avoid பண்ணு
var name = "Alice";

// let — block-scoped, reassign பண்ணலாம்
let score = 100;
score = 200; // ✅ Allowed

// const — block-scoped, reassign பண்ண முடியாது
const PI = 3.14159;
// PI = 3; // ❌ TypeError: Assignment to constant variable

// && (AND) — இரண்டும் true-ஆ இருக்கணும்
console.log(true && true);   // true
console.log(true && false);  // false

// || (OR) — ஒண்ணு true-ஆ இருந்தாலும் போதும்
console.log(false || true);  // true

// ! (NOT) — value-ஐ invert பண்ணும்
console.log(!true);  // false

// ?? (Nullish Coalescing — ES2020)
const name = null ?? "Guest"; // null/undefined-க்கு மட்டும் trigger
const port = 0 ?? 3000;       // 0 (0 is NOT null/undefined)

// Falsy — if block run ஆகாது
if (0)         { /* run ஆகாது */ }
if ("")        { /* run ஆகாது */ }
if (null)      { /* run ஆகாது */ }

// Truthy — if block run ஆகும்
if ("0")  { /* WILL run — non-empty string */ }
if ([])   { /* WILL run — empty array truthy! */ }
if ({})   { /* WILL run — empty object truthy! */ }

// Double negation trick — boolean-ஆ convert பண்ண
console.log(!!"hello"); // true
console.log(!!"");      // false
console.log(!!0);       // false

// String + anything = string concatenation
"5" + 3;       // "53"  ← number string-ஆ coerce ஆகும்
"5" + true;    // "5true"

// Arithmetic operators (+ தவிர) number-க்கு coerce பண்ணும்
"5" - 3;       // 2
"5" * "2";     // 10
true + true;   // 2    ← booleans 1-ஆ coerce ஆகும்

// Comparison coercion
"5" == 5;      // true  ← == coercion பண்ணும்
"5" === 5;     // false ← === coercion இல்ல

let score = 85;

if (score >= 90) {
  console.log("Grade: A");
} else if (score >= 80) {
  console.log("Grade: B");  // ← இது run ஆகும்
} else if (score >= 70) {
  console.log("Grade: C");
} else {
  console.log("Grade: F");
}

// condition ? valueIfTrue : valueIfFalse
let age = 20;
let status = age >= 18 ? "Adult" : "Minor";
console.log(status); // "Adult"

let day = "Monday";

switch (day) {
  case "Monday":
  case "Tuesday":
  case "Wednesday":
  case "Thursday":
  case "Friday":
    console.log("Weekday");
    break;
  case "Saturday":
  case "Sunday":
    console.log("Weekend");
    break;
  default:
    console.log("Unknown day");
}

// for loop
for (let i = 0; i < 5; i++) {
  console.log(i); // 0, 1, 2, 3, 4
}

// while loop
let count = 0;
while (count < 3) {
  console.log(count++);
}

// for...of — values-ஐ iterate பண்ண
const fruits = ["apple", "banana", "cherry"];
for (const fruit of fruits) {
  console.log(fruit);
}

// for...in — keys/indices-ஐ iterate பண்ண
const user = { name: "Alice", age: 25 };
for (const key in user) {
  console.log(key, user[key]);
}

// break — loop-ஐ முழுவதும் exit பண்ணும்
for (let i = 0; i < 10; i++) {
  if (i === 5) break;
  console.log(i); // 0, 1, 2, 3, 4
}

// continue — current iteration skip பண்ணும்
for (let i = 0; i < 5; i++) {
  if (i === 2) continue;
  console.log(i); // 0, 1, 3, 4 (2 skip ஆகும்)
}

// Function Declaration — hoisted, define பண்றதுக்கு முன்னாடியே call பண்ணலாம்
function greet(name) {
  return `Hello, ${name}!`;
}
console.log(greet("Alice")); // "Hello, Alice!"

// Function Expression — hoisted இல்ல
const greet2 = function(name) {
  return `Hi, ${name}!`;
};

// Arrow Function (ES6) — concise syntax
const greet3 = (name) => `Hey, ${name}!`;
const double = n => n * 2;   // single param
const add = (a, b) => a + b; // implicit return

// Default parameters (ES6)
