}
console.log(createUser("Bob"));           // { name: 'Bob', role: 'viewer', active: true }
console.log(createUser("Alice", "admin")); // { name: 'Alice', role: 'admin', active: true }

// Rest parameters — remaining args-ஐ array-ல collect பண்ணும்
function sum(...numbers) {
  return numbers.reduce((acc, n) => acc + n, 0);
}
console.log(sum(1, 2, 3, 4, 5)); // 15

function createCounter() {
  let count = 0; // private variable
  return {
    increment: () => ++count,
    decrement: () => --count,
    value: () => count
  };
}

const counter = createCounter();
console.log(counter.increment()); // 1
console.log(counter.increment()); // 2
console.log(counter.value());     // 2

const numbers = [1, 2, 3, 4, 5];

// map — ஒவ்வொரு element-ஐயும் transform பண்ணும்
const doubled = numbers.map(n => n * 2);
console.log(doubled); // [2, 4, 6, 8, 10]

// filter — condition pass ஆகுறவற்றை மட்டும் வை
const evens = numbers.filter(n => n % 2 === 0);
console.log(evens); // [2, 4]

// reduce — single value-ஆ accumulate பண்ணும்
const total = numbers.reduce((acc, n) => acc + n, 0);
console.log(total); // 15

// Global scope — எங்கயும் accessible
const globalVar = "நான் global";

function myFunction() {
  // Function scope — இந்த function-க்கு உள்ளே மட்டும்
  const funcVar = "நான் function-scoped";

