}

// var — hoisted, undefined-ஆ initialise ஆகும்
console.log(x); // undefined (ReferenceError இல்ல!)
var x = 5;

// let/const — hoisted ஆனா initialise ஆகல (Temporal Dead Zone)
// console.log(y); // ❌ ReferenceError
let y = 10;

// Function declarations — fully hoisted
greet(); // ✅ works
function greet() { console.log("Hello!"); }

// Function expressions — hoisted இல்ல
// sayHi(); // ❌ ReferenceError
const sayHi = () => console.log("Hi!");

// TDZ — block ஆரம்பிக்கிறதிலிருந்து declaration வரை
{
