// Math.random() → [0, 1) — 1 தவிர
Math.random();

// min மற்றும் max-க்கு இடையே random integer
function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

console.log(randomInt(1, 6));   // dice roll: 1-6

