const user = {
  name: "Alice",
  greet() {
    console.log(`Hi, I'm ${this.name}`);
  }
};
user.greet(); // "Hi, I'm Alice"

// 3. Constructor / class — new instance-ஐ refer பண்ணும்
class Person {
  constructor(name) {
    this.name = name;
  }
  greet() {
    return `Hello, I'm ${this.name}`;
  }
}
const alice = new Person("Alice");
alice.greet(); // "Hello, I'm Alice"

const timer = {
  count: 0,
  // Regular function — callback-ல 'this' lost ஆகும்
  startBroken() {
    setInterval(function() {
      this.count++; // ❌ 'this' is Window!
    }, 1000);
  },
  // Arrow function — surrounding scope-ல இருந்து inherit பண்ணும்
  start() {
    setInterval(() => {
      this.count++; // ✅ 'this' is timer
      console.log(this.count);
    }, 1000);
  }
};

function introduce(greeting, punctuation) {
  return `${greeting}, I'm ${this.name}${punctuation}`;
}

const person = { name: "Alice" };

// call() — immediately invoke, args separately
introduce.call(person, "Hello", "!");  // "Hello, I'm Alice!"

// apply() — immediately invoke, args as array
introduce.apply(person, ["Hi", "."]); // "Hi, I'm Alice."

// bind() — 'this' lock பண்ணி new function return பண்ணும்
const aliceIntro = introduce.bind(person);
aliceIntro("Hey", "?"); // "Hey, I'm Alice?"

// Modern selectors (first match return பண்ணும்)
document.querySelector(".btn");     // class-ல
document.querySelector("#title");   // id-ல
document.querySelector("h1");       // tag-ல

// All matches — NodeList return பண்ணும்
document.querySelectorAll(".card");

// Legacy
document.getElementById("title");
document.getElementsByClassName("btn");

const el = document.querySelector("#title");

el.textContent = "New Title";                    // safe — HTML இல்ல
el.innerHTML = "<strong>Bold Title</strong>";    // HTML parse பண்ணும்

el.setAttribute("data-id", "42");
el.classList.add("active");
el.classList.remove("hidden");
el.classList.toggle("visible");

el.style.color = "red";
el.style.backgroundColor = "#f0f0f0";

