const merged = [...[1, 2], ...[3, 4]]; // [1, 2, 3, 4]
const combined = { ...{ a: 1 }, ...{ b: 2 } }; // { a: 1, b: 2 }

const user = { profile: { name: "Alice" } };

// Optional chaining (?.) — ES2020
console.log(user?.profile?.name);  // "Alice"
console.log(user?.address?.city);  // undefined (error இல்ல!)

// Nullish coalescing (??) — null/undefined-க்கு மட்டும்
const port = null ?? 3000;   // 3000
const count = 0 ?? 100;      // 0 (0 is not null/undefined)

// Logical assignment — ES2021
let a = null;
a ??= "default"; // a is now "default"

// math.js — Named exports
export const PI = 3.14159;
export function add(a, b) { return a + b; }

// utils.js — Default export
export default function formatDate(date) {
  return date.toLocaleDateString();
}

// main.js — Importing
import formatDate from "./utils.js";
import { PI, add } from "./math.js";
import * as MathUtils from "./math.js";

